import numpy as np

def calculate_distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    best_node = None
    min_time = float('inf')

    for idx, customer in enumerate(unvisited_customers):
        # Calculate time to travel directly to customer
        direct_distance = calculate_distance(cur_truck_pos, customer)
        direct_time = direct_distance / 1.0  # Assuming speed of 1 unit per time step

        # Calculate time to wait at current customer position
        wait_distance = calculate_distance(cur_truck_pos, all_truck_pos[-1])
        wait_time = wait_distance / 1.0  # Assuming speed of 1 unit per time step

        # Compare total time for both options
        if direct_time < wait_time:
            total_time = direct_time
        else:
            total_time = wait_time + 10  # Assuming 10 time steps for waiting

        if total_time < min_time:
            min_time = total_time
            best_node = idx

    return best_node
